const userId = $json.user_id || "U001";
const message = ($json.message || "").toLowerCase();

// Dataset reducido de prueba para Carmen
const transactions = [
  {
    transaction_id: "T001",
    user_id: "U001",
    date: "2026-01-01",
    description: "Pensión Seguridad Social",
    merchant: "Seguridad Social",
    amount: 980,
    category: "pension",
    balance_after: 2430
  },
  {
    transaction_id: "T002",
    user_id: "U001",
    date: "2026-01-03",
    description: "Farmacia Central",
    merchant: "Farmacia Central",
    amount: -18.5,
    category: "farmacia",
    balance_after: 2411.5
  },
  {
    transaction_id: "T003",
    user_id: "U001",
    date: "2026-01-05",
    description: "Supermercado",
    merchant: "Mercadona",
    amount: -42.3,
    category: "supermercado",
    balance_after: 2369.2
  },
  {
    transaction_id: "T004",
    user_id: "U001",
    date: "2026-01-07",
    description: "Recibo luz",
    merchant: "Endesa",
    amount: -64.8,
    category: "luz",
    balance_after: 2304.4
  },
  {
    transaction_id: "T005",
    user_id: "U001",
    date: "2026-01-10",
    description: "Comisión mantenimiento",
    merchant: "Banco",
    amount: -15,
    category: "comision",
    balance_after: 2289.4
  }
];

const userTransactions = transactions.filter(t => t.user_id === userId);

let answer = "";
let intent_detected = "";
let source_records = [];

if (message.includes("pensión") || message.includes("pension")) {
  intent_detected = "consulta_pension";
  const pension = userTransactions.find(t => t.category === "pension");

  if (pension) {
    answer = `Sí, Carmen. La pensión aparece registrada el ${pension.date} por un importe de ${pension.amount} euros.`;
    source_records = [pension.transaction_id];
  } else {
    answer = "No he encontrado ningún ingreso de pensión en los movimientos disponibles.";
  }

} else if (message.includes("farmacia")) {
  intent_detected = "consulta_gasto_farmacia";
  const farmacia = userTransactions.filter(t => t.category === "farmacia");
  const total = farmacia.reduce((sum, t) => sum + Math.abs(t.amount), 0);

  answer = `Carmen, según los movimientos disponibles, has gastado ${total.toFixed(2)} euros en farmacia.`;
  source_records = farmacia.map(t => t.transaction_id);

} else if (message.includes("saldo")) {
  intent_detected = "consulta_saldo";
  const lastTransaction = userTransactions[userTransactions.length - 1];

  answer = `Carmen, el último saldo disponible es de ${lastTransaction.balance_after.toFixed(2)} euros.`;
  source_records = [lastTransaction.transaction_id];

} else {
  intent_detected = "consulta_no_reconocida";
  answer = "Puedo ayudarte a consultar la pensión, el saldo o gastos como farmacia. Prueba con una de esas preguntas.";
}

return [
  {
    json: {
      user_id: userId,
      original_message: message,
      intent_detected,
      answer,
      source_records,
      numeric_data_from_dataset: true,
      module: "C4_GESTION_FINANCIERA_MOCK"
    }
  }
];
